#include<stdio.h>
int main()
{
int n,i,j,p,flag=0,cnt=0;
char A[105];
scanf("%d",&n);
scanf("%s",A);
for(i=1;i<n;i++)
{
flag=0;
if(A[i]==A[0])
{
p=1;
for(j=i+1;p<i;j++)
{
if(j==n)
{
flag=1;
break;
}
else if(A[j]!=A[p])
{
flag=1;
break;
}
else
{
p++;
}
}
if(flag==0 && p>cnt)
{
cnt=p;
}
}
}
if(cnt!=0)
{
 printf("%d\n",(n-cnt)+1);
}
else
{
printf("%d\n",n);
}
}

